import React, { useRef } from 'react';
import { VoucherFormToolbar, VoucherFormStatusGroup } from '../../../../../components/voucher';
import { ValidationErrorBanner } from '../../../../../components/layout';
import { useTopbarAutoHideOnScroll, useVoucherFormShellHeight, useFormEmbedSlideout } from '../../../../../components/form';
import { formatProcessingLevelFromOptions } from '../../../../../utils/voucherProcessingLevelOptions';
import { resolveVoucherViewModeHint } from '../../../../../utils/voucherProcessingLevelDisplay';
import type { PurchaseInvoiceFormProps } from '../types/purchaseInvoice.types';
import { usePurchaseInvoiceFormController } from '../hooks/usePurchaseInvoiceFormController';
import { PurchaseInvoiceHeaderSection } from './PurchaseInvoiceHeaderSection';
import { PurchaseInvoiceLinesSection } from './PurchaseInvoiceLinesSection';
import { PurchaseInvoiceFooterSection } from './PurchaseInvoiceFooterSection';
import { PurchaseInvoiceFormModals } from './PurchaseInvoiceFormModals';
import styles from '../../../../../styles/documentForm.module.css';

export const PurchaseInvoiceFormParent: React.FC<PurchaseInvoiceFormProps> = props => {
  const vm = usePurchaseInvoiceFormController(props);
  const embedSlideout = useFormEmbedSlideout();
  const shellRef = useRef<HTMLDivElement>(null);
  const scrollRef = useRef<HTMLDivElement>(null);
  useVoucherFormShellHeight(shellRef, !embedSlideout);
  useTopbarAutoHideOnScroll(scrollRef, !embedSlideout);

  if (vm.showInitialLoading) {
    return (
      <div className={styles.loading} data-testid={vm.tid('loading')}>
        Đang tải...
      </div>
    );
  }

  const {
    cfg,
    title,
    isNew,
    code,
    status,
    processingLevel,
    processingOpts,
    toolbarMode,
    isStatusLocked,
    isViewMode,
    saving,
    posting,
    saveLabel,
    hasSearchNav,
    searchNavIndex,
    searchResultIds,
    navigateToSearchId,
    handleBack,
    setShowApproveModal,
    handleCopy,
    setShowPrintModal,
    setShowSearchSlideout,
    handleNew,
    handleEdit,
    handleSave,
    handleCancel,
    setShowDeleteModal,
    toolbarDisabledReasons,
    formPermissions,
    validationErrors,
    bannerClosed,
    bannerExpanded,
    setBannerExpanded,
    setBannerClosed,
    validationBannerId,
    copySourceVoucherCode,
    fieldLock,
    canViewLedger,
    setShowLedgerModal,
  } = vm;

  const processingLevelLabel = formatProcessingLevelFromOptions(processingLevel, processingOpts);
  const canActOnDraft = !isNew && status === 'Draft' && !isStatusLocked;
  const canEditWhenView = !isNew && !isStatusLocked;
  const { viewSectionClass } = fieldLock;

  return (
    <div
      ref={shellRef}
      className={[
        styles.pageVoucher,
        embedSlideout ? styles.pageVoucherSlideoutEmbed : '',
      ].filter(Boolean).join(' ')}
      data-voucher-form-shell
      data-form-embed-slideout={embedSlideout || undefined}
      data-testid={vm.tid('form')}
    >
      {!embedSlideout && (
      <div className={styles.pageFormHeader}>
        <div className={styles.stickyTop}>
          <VoucherFormToolbar
            testIdPrefix={cfg.testIdPrefix}
            title={isNew ? `Tạo ${title}` : `${title} — ${code || '...'}`}
            processingLevelBadge={
              !isNew ? <VoucherFormStatusGroup processingLevelLabel={processingLevelLabel} /> : undefined
            }
            formMode={toolbarMode}
            viewModeHint={resolveVoucherViewModeHint({
              formMode: toolbarMode,
              isNew,
              status,
              processingLevel,
              canEditWhenView,
            })}
            copySourceVoucherCode={copySourceVoucherCode}
            canApprove={canActOnDraft}
            showPostButton={false}
            canPost={false}
            canCopy={!isNew}
            canPrint={!isNew}
            canEdit={canEditWhenView}
            canDelete={canActOnDraft}
            showNewButton={formPermissions?.canCreate ?? false}
            saving={saving}
            posting={posting}
            saveLabel={saveLabel}
            disabledReasons={toolbarDisabledReasons}
            searchNav={
              hasSearchNav
                ? {
                    index: searchNavIndex,
                    total: searchResultIds.length,
                    onFirst: () => navigateToSearchId(searchResultIds[0]),
                    onPrev: () => navigateToSearchId(searchResultIds[searchNavIndex - 1]),
                    onNext: () => navigateToSearchId(searchResultIds[searchNavIndex + 1]),
                    onEnd: () => navigateToSearchId(searchResultIds[searchResultIds.length - 1]),
                  }
                : undefined
            }
            onBack={handleBack}
            onApprove={() => setShowApproveModal(true)}
            onPost={() => {}}
            canViewLedger={canViewLedger}
            onViewLedger={() => setShowLedgerModal(true)}
            onCopy={handleCopy}
            onPrint={() => setShowPrintModal(true)}
            onSearch={() => setShowSearchSlideout(true)}
            onNew={handleNew}
            onEdit={handleEdit}
            onSave={handleSave}
            onCancel={handleCancel}
            onDelete={() => setShowDeleteModal(true)}
            insetShell
          />
        </div>
      </div>
      )}

      <div ref={scrollRef} className={styles.pageFormScroll} data-testid={vm.tid('form-scroll')}>
        <ValidationErrorBanner
          errors={validationErrors}
          closed={bannerClosed}
          expanded={bannerExpanded}
          onToggle={() => setBannerExpanded(v => !v)}
          onClose={() => setBannerClosed(true)}
          bannerId={validationBannerId}
        />

        <PurchaseInvoiceHeaderSection vm={vm} />
        <PurchaseInvoiceLinesSection vm={vm} />
      </div>

      <div className={styles.pageFormFooter} data-testid={vm.tid('form-footer')}>
        <PurchaseInvoiceFooterSection vm={vm} viewSectionClass={viewSectionClass} />
      </div>

      <PurchaseInvoiceFormModals vm={vm} />
    </div>
  );
};
