import React from 'react';
import { Button, Modal } from '@linm-soft-org/linm-web-common-components';
import { UnsavedChangesModal } from '../../../../../components/form';
import {
  VoucherSearchSlideout,
  VoucherPrintModal,
  ProcessingLevelApproveModal,
  VoucherPostedLedgerModal,
} from '../../../../../components/voucher';
import { formatProcessingLevelFromOptions } from '../../../../../utils/voucherProcessingLevelOptions';
import type { usePurchaseInvoiceFormController } from '../hooks/usePurchaseInvoiceFormController';

type Vm = ReturnType<typeof usePurchaseInvoiceFormController>;

export const PurchaseInvoiceFormModals: React.FC<{ vm: Vm }> = ({ vm }) => {
  const df = vm.styles;
  const {
    cfg,
    title,
    isNew,
    code,
    processingLevel,
    processingOpts,
    showSearchSlideout,
    setShowSearchSlideout,
    handleOpenFromSearch,
    showApproveModal,
    setShowApproveModal,
    handleApproveConfirm,
    approving,
    showPrintModal,
    setShowPrintModal,
    handlePrintConfirm,
    printing,
    showUnsavedModal,
    cancelLeave,
    confirmLeave,
    tid,
    showDeleteModal,
    setShowDeleteModal,
    handleDelete,
    deleting,
    showPostModal,
    setShowPostModal,
    handlePost,
    posting,
    canViewLedger,
    showLedgerModal,
    setShowLedgerModal,
    id,
  } = vm;

  return (
    <>
      <VoucherSearchSlideout
        isOpen={showSearchSlideout}
        onClose={() => setShowSearchSlideout(false)}
        title={`Tìm ${title}`}
        testIdPrefix={cfg.testIdPrefix}
        listScope={cfg.searchListScope}
        fetchList={cfg.fetchList}
        onOpenVoucher={(voucherId, resultIds) => handleOpenFromSearch(voucherId, resultIds)}
        processingLevelFilterOptions={processingOpts}
        formatProcessingLevel={level => formatProcessingLevelFromOptions(level, processingOpts)}
      />

      <ProcessingLevelApproveModal
        isOpen={showApproveModal}
        onClose={() => setShowApproveModal(false)}
        currentLevel={processingLevel}
        levelOptions={processingOpts}
        onConfirm={handleApproveConfirm}
        saving={approving}
        testIdPrefix={cfg.testIdPrefix}
      />

      <VoucherPrintModal
        isOpen={showPrintModal}
        onClose={() => setShowPrintModal(false)}
        voucherTitle={!isNew ? `${title} — ${code || '...'}` : undefined}
        onPrint={handlePrintConfirm}
        printing={printing}
        testIdPrefix={cfg.testIdPrefix}
      />

      <UnsavedChangesModal
        isOpen={showUnsavedModal}
        onStay={cancelLeave}
        onLeave={confirmLeave}
        data-testid={tid('unsaved-modal')}
      />

      <Modal isOpen={showDeleteModal} onClose={() => setShowDeleteModal(false)} title="Xác nhận xóa">
        <p>Bạn có chắc muốn xóa hóa đơn này?</p>
        <div className={df.modalActions}>
          <Button variant="secondary" onClick={() => setShowDeleteModal(false)}>
            Hủy
          </Button>
          <Button variant="danger" data-testid={tid('delete-confirm-btn')} onClick={handleDelete} loading={deleting}>
            Xóa
          </Button>
        </div>
      </Modal>

      <Modal
        isOpen={showPostModal}
        onClose={() => setShowPostModal(false)}
        title="Xác nhận ghi sổ"
        data-testid={tid('post-modal')}
      >
        <p>
          Ghi sổ hóa đơn <strong>{code}</strong>? Sau khi ghi sổ không thể chỉnh sửa.
        </p>
        <div className={df.modalActions}>
          <Button variant="secondary" onClick={() => setShowPostModal(false)} data-testid={tid('post-cancel')}>
            Hủy
          </Button>
          <Button variant="primary" data-testid={tid('post-confirm-btn')} onClick={handlePost} loading={posting}>
            Ghi sổ
          </Button>
        </div>
      </Modal>

      {!isNew && id && canViewLedger && (
        <VoucherPostedLedgerModal
          isOpen={showLedgerModal}
          onClose={() => setShowLedgerModal(false)}
          voucherTitle={!isNew ? `${title} — ${code || '...'}` : undefined}
          fetchPostedLedger={() => cfg.getPostedLedger(id)}
          fetchPostingStatus={() => cfg.getPostingStatus(id)}
          testIdPrefix={cfg.testIdPrefix}
        />
      )}
    </>
  );
};
